import json
import pickle
from io import BytesIO

def lambda_handler(event, context):
    try:
        # Validate the event source (API Gateway)
        if 'requestContext' not in event or 'httpMethod' not in event['requestContext']:
            raise ValueError("Invalid event source")

        # Extract and validate payload
        payload = event.get('body', None)
        if not payload:
            raise ValueError("No payload provided")

        # Deserialize the payload using pickle
        with BytesIO(payload.encode('utf-8')) as f:
            data = pickle.load(f)

        # Process the deserialized data (example: print it)
        print(data)

        return {
            'statusCode': 200,
            'body': json.dumps({'message': 'Payload processed successfully'})
        }

    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }